from difflib import SequenceMatcher
def token_f1(a,b):
    a_tokens = a.split()
    b_tokens = b.split()
    if not a_tokens or not b_tokens:
        return 0.0
    a_counts = {}
    for t in a_tokens:
        a_counts[t] = a_counts.get(t,0)+1
    overlap=0
    for t in b_tokens:
        if a_counts.get(t,0)>0:
            overlap += 1
            a_counts[t] -= 1
    prec = overlap/len(b_tokens)
    rec = overlap/len(a_tokens)
    if prec+rec==0:
        return 0.0
    return 2*prec*rec/(prec+rec)

def seq_ratio(a,b):
    return SequenceMatcher(None,a,b).ratio()

